{"version":3,"sources":["components/ActionCard.uvue"],"sourcesContent":["<template>\r\n  <view class=\"action-card\" :class=\"cardClass\" @tap=\"onTap\">\r\n    <view class=\"action-icon-wrap\" :class=\"iconWrapClass\">\r\n      <image class=\"action-icon-img\" :src=\"actionIconSrc\" mode=\"aspectFit\"></image>\r\n    </view>\r\n    <view class=\"action-info\">\r\n      <text class=\"action-name\">{{ props.actionName }}</text>\r\n      <text class=\"action-duration-text\">{{ props.actionDuration }}秒</text>\r\n    </view>\r\n    <text class=\"action-arrow\" :class=\"arrowClass\">›</text>\r\n  </view>\r\n</template>\r\n\r\n<script setup lang=\"uts\">\r\ntype ActionVariant = 'recommend' | 'library'\r\n\r\nconst props = withDefaults(defineProps<{\r\n  actionId: string\r\n  actionName: string\r\n  actionDuration: number\r\n  variant?: ActionVariant\r\n}>(), {\r\n  variant: 'library'\r\n})\r\n\r\nconst emit = defineEmits<{\r\n  (e: 'actionTap', actionId: string): void\r\n}>()\r\n\r\nfunction actionIconPath(): string {\r\n  if (props.actionId === 'eye_blink') return '/static/icons/eye_blink.png'\r\n  if (props.actionId === 'eye_rotate') return '/static/icons/eye_rotate.png'\r\n  if (props.actionId === 'neck_rotate') return '/static/icons/neck_rotate.png'\r\n  if (props.actionId === 'shoulder_roll') return '/static/icons/shoulder_roll.png'\r\n  if (props.actionId === 'neck_stretch') return '/static/icons/neck_stretch.png'\r\n  if (props.actionId === 'core_tighten') return '/static/icons/core_tighten.png'\r\n  if (props.actionId === 'heel_raise') return '/static/icons/heel_raise.png'\r\n  if (props.actionId === 'deep_breath') return '/static/icons/deep_breath.png'\r\n  if (props.actionId === 'far_gaze') return '/static/icons/far_gaze.png'\r\n  return '/static/icons/eye_blink.png'\r\n}\r\n\r\nfunction getCardClass(): string {\r\n  return props.variant === 'recommend' ? 'card-recommend' : 'card-library'\r\n}\r\n\r\nfunction getIconWrapClass(): string {\r\n  return props.variant === 'recommend' ? 'icon-wrap-recommend' : 'icon-wrap-library'\r\n}\r\n\r\nfunction getArrowClass(): string {\r\n  return props.variant === 'recommend' ? 'arrow-recommend' : 'arrow-library'\r\n}\r\n\r\nconst cardClass = computed<string>(getCardClass)\r\nconst iconWrapClass = computed<string>(getIconWrapClass)\r\nconst arrowClass = computed<string>(getArrowClass)\r\nconst actionIconSrc = computed<string>(actionIconPath)\r\n\r\nfunction onTap(): void {\r\n  emit('actionTap', props.actionId)\r\n}\r\n</script>\r\n\r\n<style scoped>\r\n.action-card {\r\n  flex-direction: row;\r\n  align-items: center;\r\n  padding: 12px 16px;\r\n  margin: 4px 16px;\r\n  background-color: #F8F9FA;\r\n  border-radius: 12px;\r\n  border-width: 0;\r\n  box-shadow: 0 1px 4px rgba(0, 0, 0, 0.03);\r\n}\r\n.card-recommend {\r\n  background-color: #F0F9F4;\r\n  border-left-width: 4px;\r\n  border-left-color: #2ECC71;\r\n  border-left-style: solid;\r\n}\r\n.card-library {\r\n  background-color: #FFFFFF;\r\n  border-width: 1px;\r\n  border-color: #ECF0F1;\r\n  border-style: solid;\r\n}\r\n.action-icon-wrap {\r\n  width: 46px;\r\n  height: 46px;\r\n  border-radius: 23px;\r\n  align-items: center;\r\n  justify-content: center;\r\n  margin-right: 12px;\r\n}\r\n.icon-wrap-recommend {\r\n  background-color: #D5F5E3;\r\n}\r\n.icon-wrap-library {\r\n  background-color: #F0F3F4;\r\n}\r\n.action-icon-img {\r\n  width: 42px;\r\n  height: 42px;\r\n}\r\n.action-info {\r\n  flex: 1;\r\n  flex-direction: column;\r\n}\r\n.action-name {\r\n  font-size: 15px;\r\n  font-weight: bold;\r\n  color: #2C3E50;\r\n}\r\n.action-duration-text {\r\n  font-size: 12px;\r\n  color: #95A5A6;\r\n  margin-top: 2px;\r\n}\r\n.action-arrow {\r\n  font-size: 22px;\r\n  font-weight: bold;\r\n}\r\n.arrow-recommend {\r\n  color: #2ECC71;\r\n}\r\n.arrow-library {\r\n  color: #BDC3C7;\r\n}\r\n</style>\r\n"],"names":[],"mappings":";;;;;;;;;;;;;;;;;;;;;;;;;;YAgBA,IAAM,QAAQ;YASd,IAAA,KAAA,OAAA,MAAA,CAAA,CAAA,OAAA,yBAAA,GAAA,CAAA,EAAA;gBAAA,MA